const input = $input.first().json;
const body = input.body || input;
const data = body.data || {};

// Teléfono está en recipientKeyIndexes como JID
let jid = data.recipientKeyIndexes || '';
let phone = jid.split('@')[0] || 'unknown';

// Instancia - buscar en varios lugares
let instance = body.instance || body.instanceName || '';
if (instance === 'messages.upsert') {
  // Si instance tiene el evento, buscar en otro lado
  instance = body.apikey || body.server || data.executionMode?.split('/')[2]?.split('.')[0] || 'default';
}

// Mensaje - buscar en conversation o message
let content = data.conversation || data.message?.conversation || '';
if (!content && data.message) {
  content = data.message.extendedTextMessage?.text || JSON.stringify(data.message);
}
if (!content) content = 'mensaje recibido';

// Nombre
let name = data.pushName || 'Cliente';

return {
  phone,
  content: content.substring(0, 200),
  instance,
  name,
  event: body.event || 'unknown'
};

